package com.kalyani.car_rental_backend.emergency.entity;import com.kalyani.car_rental_backend.user.entity.User;import jakarta.persistence.*;@Entity@Table(name="emergency_contacts")public class EmergencyContact{@Id@GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@ManyToOne(optional=false,fetch=FetchType.LAZY)private User user;@Column(nullable=false)private String name;@Column(nullable=false)private String phone;private String relationship;public Long getId(){return id;}public User getUser(){return user;}public void setUser(User v){user=v;}public String getName(){return name;}public void setName(String v){name=v;}public String getPhone(){return phone;}public void setPhone(String v){phone=v;}public String getRelationship(){return relationship;}public void setRelationship(String v){relationship=v;}}
